def count_provinces(isConnected):
    n = len(isConnected)
    seen = [False] * n
    def dfs(i):
        stack = [i]
        while stack:
            u = stack.pop()
            if seen[u]:
                continue
            seen[u] = True
            row = isConnected[u]
            for v in range(n):
                if row[v] and not seen[v]:
                    stack.append(v)
    ans = 0
    for i in range(n):
        if not seen[i]:
            ans += 1
            dfs(i)
    return ans

